(23,'134741487',3,'2025-09-10','2025-10-18',26,'Rákóczi 61, 62','Rákóczi 62 oszlop a villanyban és Rákóczi 61 üzemen kívüli bontás','Létai Péter műszaki ellenőr kollégánk az alábbi hiányosságokat tapasztalta. Kérem az üzemen kívüli oszlopot a villamos hálózat alól kibontani, a második képen látható üzemen kívüli vezetékeket bontani szíveskedjetek.',1,NULL,NULL,1,1,'2025-09-22 17:37:21','2025-09-29 16:41:56'),
(24,'134741710',3,'2025-09-10','2025-10-18',13,'Öregfalu','üzemen kívüli oszlopsor bontása','Visszatérő panaszunk rendezésében kérem segítségedet. A földterület bérlője rendszeresen, minden évben panaszt nyújtott be a térképen jelölt szántóföldet átszelő réz léges irányunk bontását illetően. Eljutottunk odáig, hogy az FTTH elkészültével  üzemen kívülivé vált a légkábel. Kérem, hogy a térképen jelölt részen a légkábelt és az oszlopokat bontani szíveskedjetek. További infó: Létai Pétertől',1,NULL,NULL,1,1,'2025-09-22 17:38:38','2025-10-02 15:23:34'),
(25,'134752165',3,'2025-09-11','2025-10-19',28,'Kossuth u. 149, 151, 153','Légkábel léccel kitámasztva','Létai Péter műszaki ellenőr kolléga a képeken látható állapotot tapasztalta. Kérem a légkábelt beszabályozni úgy hogy a legalacsonyabb ponton, kapubejáró felett a 4,5m-t, út felett 5,5m átfeszítési magasságot tudja.',1,NULL,NULL,1,1,'2025-09-22 17:39:39','2025-10-15 15:53:47'),
